mapper.select:
SELECT COUNT(*) FROM supply_connections
WHERE demand_id = #{demandId}
  AND supply_id = #{supplyId}
  AND status = 'negotiating'

mapper.update:
UPDATE supply_connections SET status = #{status}, last_update = CURDATE()
, completed_date = CURDATE()
WHERE id = #{id}

UPDATE supply_connections
SET notes = #{notes},
    last_update = CURDATE(),
    updated_at = #{updatedAt}
WHERE id = #{id}
